<template>
  <cool-light-box :items="items" :index="index" @close="index = null" />
</template>

<script>
import CoolLightBox from 'vue-cool-lightbox';
import 'vue-cool-lightbox/dist/vue-cool-lightbox.min.css';

export default {
  components: {
    CoolLightBox,
  },
  data() {
    return {
      index: null,
      items: [],
    };
  },

  methods: {
    modalOpenEventHandler({ index, data }) {
      this.isOpen = !this.isOpen;
      const { folder, photos } = data;
      this.items = photos.map(p => `https://p-strge.s3.eu-central-1.amazonaws.com/assets/albums/${folder}/${p}.jpg`);

      this.index = index;
    },
  },
  mounted() {
    this.$eventBus.$on('open-modal', this.modalOpenEventHandler);
  },
};
</script>